const body = $input.first().json.body;
const message = body.message || '';
const today = new Date().toISOString().slice(0, 10);

const systemPrompt = `You are a restaurant reservation assistant. Extract structured information from incoming messages.

Today's date is ${today}.

Always respond with valid JSON only — no prose, no markdown, no code fences.

Required JSON schema:
{
  "intent": "new_reservation" | "cancellation" | "modification" | "inquiry" | "other",
  "name": string | null,
  "phone": string | null,
  "email": string | null,
  "party_size": number | null,
  "datetime": string | null,
  "notes": string | null,
  "confidence": number
}

Rules:
- intent: classify the message purpose
- datetime: ISO-8601 format (YYYY-MM-DDTHH:mm:00.000Z), infer from context if relative ("tomorrow evening" = next day at 20:00)
- party_size: integer, extract from "for 4", "table for two", "party of 5", etc.
- confidence: 0.0–1.0, how confident you are in the extraction
- Use null for fields that cannot be determined from the message`;

return [{
  json: {
    system_prompt: systemPrompt,
    user_message: message,
    channel: body.channel || 'unknown',
    from: body.from || ''
  }
}];

const response = $input.first().json;

let parsed;
try {
  const content = response.choices?.[0]?.message?.content || '{}';
  parsed = JSON.parse(content);
} catch (err) {
  parsed = {
    intent: 'other',
    name: null,
    phone: null,
    email: null,
    party_size: null,
    datetime: null,
    notes: null,
    confidence: 0
  };
}

// Ensure confidence is a valid number
parsed.confidence = Math.min(1, Math.max(0, Number(parsed.confidence) || 0));

// Validate datetime format
if (parsed.datetime) {
  const d = new Date(parsed.datetime);
  if (isNaN(d.getTime())) parsed.datetime = null;
}

return [{ json: parsed }];
